// MissionList.jsx
import React, { useEffect, useState } from "react";
import axios from "axios";
import MissionItem from "./MissionItem";

const MissionList = ({ userId }) => {
  const [missions, setMissions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    // Lấy tất cả nhiệm vụ của người chơi từ API
    axios
      .get(`http://localhost:3001/user-missions/${userId}`)
      .then((response) => {
        setMissions(response.data);
        setLoading(false);
      })
      .catch((err) => {
        setError(err.message);
        setLoading(false);
      });
  }, [userId]);

  const handleUpdateProgress = (missionId, newProgress) => {
    axios
      .post("http://localhost:3001/user-missions/update", {
        userId,
        missionId,
        progress: newProgress,
      })
      .then(() => {
        setMissions((prevMissions) =>
          prevMissions.map((mission) =>
            mission.mission_id === missionId
              ? { ...mission, progress: newProgress }
              : mission
          )
        );
      })
      .catch((err) => {
        setError(err.message);
      });
  };

  const handleClaimReward = (missionId) => {
    axios
      .post("http://localhost:3001/user-missions/claim", {
        userId,
        missionId,
      })
      .then((response) => {
        const reward = response.data.reward;
        alert(`You received ${reward} gold!`);
        setMissions((prevMissions) =>
          prevMissions.map((mission) =>
            mission.mission_id === missionId
              ? { ...mission, claimed: true }
              : mission
          )
        );
      })
      .catch((err) => {
        setError(err.message);
      });
  };

  return (
    <div className="mission-list-container">
      <h1 className="mission-list-title">Mission List</h1>
      {loading ? (
        <p className="mission-list-loading">Loading...</p>
      ) : error ? (
        <p className="mission-list-error">Error: {error}</p>
      ) : (
        <table className="mission-table">
          <thead>
            <tr>
              <th>Mission</th>
              <th>Progress</th>
              <th>Reward</th>
              <th>Status</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {missions.map((mission) => (
              <MissionItem
                key={mission.mission_id}
                mission={mission}
                userId={userId}
                onUpdateProgress={handleUpdateProgress}
                onClaimReward={handleClaimReward}
                asTableRow={true}
              />
            ))}
          </tbody>
        </table>
      )}
      <style>{`
        .mission-list-container {
          max-width: 800px;
          margin: 32px auto;
          background: #fff;
          border-radius: 12px;
          box-shadow: 0 2px 12px rgba(0,0,0,0.08);
          padding: 32px 24px;
        }
        .mission-list-title {
          text-align: center;
          margin-bottom: 24px;
          color: #2d3748;
        }
        .mission-table {
          width: 100%;
          border-collapse: collapse;
        }
        .mission-table th, .mission-table td {
          padding: 12px 8px;
          border-bottom: 1px solid #e2e8f0;
          text-align: center;
        }
        .mission-table th {
          background: #f7fafc;
          color: #4a5568;
          font-weight: 600;
        }
        .mission-list-loading, .mission-list-error {
          text-align: center;
          color: #e53e3e;
          font-size: 18px;
        }
        @media (max-width: 600px) {
          .mission-list-container {
            padding: 12px 4px;
          }
          .mission-table th, .mission-table td {
            padding: 6px 2px;
            font-size: 13px;
          }
        }
      `}</style>
    </div>
  );
};

export default MissionList;
